1328       for (Instruction *WriteL1 : FC1.MemWrites)
1329         if (!dependencesAllowFusion(FC0, FC1, *WriteL0, *WriteL1,
1330                                     /* AnyDep */ false,
1331                                     FusionDependenceAnalysis)) {
1332           InvalidDependencies++;
1333           return false;
1334         }
1335       for (Instruction *ReadL1 : FC1.MemReads)
1336         if (!dependencesAllowFusion(FC0, FC1, *WriteL0, *ReadL1,
1337                                     /* AnyDep */ false,
1338                                     FusionDependenceAnalysis)) {
1339           InvalidDependencies++;
1340           return false;
1341         }
1342     }
1343 
1344     for (Instruction *WriteL1 : FC1.MemWrites) {
1345       for (Instruction *WriteL0 : FC0.MemWrites)
1346         if (!dependencesAllowFusion(FC0, FC1, *WriteL0, *WriteL1,
1347                                     /* AnyDep */ false,
1348                                     FusionDependenceAnalysis)) {
1349           InvalidDependencies++;
1350           return false;
1351         }
1352       for (Instruction *ReadL0 : FC0.MemReads)
1353         if (!dependencesAllowFusion(FC0, FC1, *ReadL0, *WriteL1,
1354                                     /* AnyDep */ false,
1355                                     FusionDependenceAnalysis)) {
1356           InvalidDependencies++;
1357           return false;
1358         }
1359     }
1360 
1361     // Walk through all uses in FC1. For each use, find the reaching def. If the
1362     // def is located in FC0 then it is not safe to fuse.
1363     for (BasicBlock *BB : FC1.L->blocks())
1364       for (Instruction &I : *BB)
1365         for (auto &Op : I.operands())
1366           if (Instruction *Def = dyn_cast<Instruction>(Op))
1367             if (FC0.L->contains(Def->getParent())) {
