1689     // Is there a way to keep SE up-to-date so we don't need to forget the loops
1690     // and rebuild the information in subsequent passes of fusion?
1691     // Note: Need to forget the loops before merging the loop latches, as
1692     // mergeLatch may remove the only block in FC1.
1693     SE.forgetLoop(FC1.L);
1694     SE.forgetLoop(FC0.L);
1695 
1696     // Move instructions from FC0.Latch to FC1.Latch.
1697     // Note: mergeLatch requires an updated DT.
1698     mergeLatch(FC0, FC1);
