1706     SmallVector<BasicBlock *, 8> Blocks(FC1.L->blocks());
1707     for (BasicBlock *BB : Blocks) {
1708       FC0.L->addBlockEntry(BB);
1709       FC1.L->removeBlockFromLoop(BB);
1710       if (LI.getLoopFor(BB) != FC1.L)
1711         continue;
1712       LI.changeLoopFor(BB, FC0.L);
