1714     while (!FC1.L->isInnermost()) {
1715       const auto &ChildLoopIt = FC1.L->begin();
1716       Loop *ChildLoop = *ChildLoopIt;
1717       FC1.L->removeChildLoop(ChildLoopIt);
1718       FC0.L->addChildLoop(ChildLoop);
1719     }
1720 
1721     // Delete the now empty loop L1.
1722     LI.erase(FC1.L);
1723 
1724 #ifndef NDEBUG
1725     assert(!verifyFunction(*FC0.Header->getParent(), &errs()));
1726     assert(DT.verify(DominatorTree::VerificationLevel::Fast));
1727     assert(PDT.verify());
1728     LI.verify(DT);
