1843     assert(pred_empty(FC1GuardBlock) &&
1844            "Expecting guard block to have no predecessors");
1845     assert(succ_empty(FC1GuardBlock) &&
1846            "Expecting guard block to have no successors");
1847 
1848     // Remember the phi nodes originally in the header of FC0 in order to rewire
1849     // them later. However, this is only necessary if the new loop carried
1850     // values might not dominate the exiting branch. While we do not generally
1851     // test if this is the case but simply insert intermediate phi nodes, we
1852     // need to make sure these intermediate phi nodes have different
1853     // predecessors. To this end, we filter the special case where the exiting
1854     // block is the latch block of the first loop. Nothing needs to be done
1855     // anyway as all loop carried values dominate the latch and thereby also the
1856     // exiting branch.
1857     // KB: This is no longer necessary because FC0.ExitingBlock == FC0.Latch
1858     // (because the loops are rotated. Thus, nothing will ever be added to
1859     // OriginalFC0PHIs.
1860     SmallVector<PHINode *, 8> OriginalFC0PHIs;
1861     if (FC0.ExitingBlock != FC0.Latch)
1862       for (PHINode &PHI : FC0.Header->phis())
1863         OriginalFC0PHIs.push_back(&PHI);
1864 
1865     assert(OriginalFC0PHIs.empty() && "Expecting OriginalFC0PHIs to be empty!");
