1867     // Replace incoming blocks for header PHIs first.
1868     FC1.Preheader->replaceSuccessorsPhiUsesWith(FC0.Preheader);
1869     FC0.Latch->replaceSuccessorsPhiUsesWith(FC1.Latch);
1870 
1871     // The old exiting block of the first loop (FC0) has to jump to the header
1872     // of the second as we need to execute the code in the second header block
1873     // regardless of the trip count. That is, if the trip count is 0, so the
1874     // back edge is never taken, we still have to execute both loop headers,
1875     // especially (but not only!) if the second is a do-while style loop.
1876     // However, doing so might invalidate the phi nodes of the first loop as
1877     // the new values do only need to dominate their latch and not the exiting
1878     // predicate. To remedy this potential problem we always introduce phi
1879     // nodes in the header of the second loop later that select the loop carried
1880     // value, if the second header was reached through an old latch of the
1881     // first, or undef otherwise. This is sound as exiting the first implies the
1882     // second will exit too, __without__ taking the back-edge (their
1883     // trip-counts are equal after all).
1884     FC0.ExitingBlock->getTerminator()->replaceUsesOfWith(FC0.ExitBlock,
1885                                                          FC1.Header);
1886 
1887     TreeUpdates.emplace_back(DominatorTree::UpdateType(
1888         DominatorTree::Delete, FC0.ExitingBlock, FC0.ExitBlock));
1889     TreeUpdates.emplace_back(DominatorTree::UpdateType(
1890         DominatorTree::Insert, FC0.ExitingBlock, FC1.Header));
1891 
1892     // Remove FC0 Exit Block
1893     // The exit block for FC0 is no longer needed since control will flow
1894     // directly to the header of FC1. Since it is an empty block, it can be
1895     // removed at this point.
1896     // TODO: In the future, we can handle non-empty exit blocks my merging any
1897     // instructions from FC0 exit block into FC1 exit block prior to removing
1898     // the block.
1899     assert(pred_empty(FC0.ExitBlock) && "Expecting exit block to be empty");
