1302         LLVM_DEBUG(
1303             dbgs() << "TODO: Implement pred/succ dependence handling!\n");
1304 
1305       // TODO: Can we actually use the dependence info analysis here?
1306       return false;
1307     }
1308 
1309     case FUSION_DEPENDENCE_ANALYSIS_ALL:
1310       return dependencesAllowFusion(FC0, FC1, I0, I1, AnyDep,
1311                                     FUSION_DEPENDENCE_ANALYSIS_SCEV) ||
