574       ParallelAccessGroups; // For scalable 'contains' check.
575   if (ParallelAccesses) {
576     for (const MDOperand &MD : drop_begin(ParallelAccesses->operands())) {
577       MDNode *AccGroup = cast<MDNode>(MD.get());
