1088   bool collectMovablePreheaderInsts(
1089       const FusionCandidate &FC0, const FusionCandidate &FC1,
1090       SmallVector<Instruction *, 4> &SafeToHoist,
1091       SmallVector<Instruction *, 4> &SafeToSink) const {
1092     BasicBlock *FC1Preheader = FC1.Preheader;
1093     // Save the instructions that are not being hoisted, so we know not to hoist
1094     // mem insts that they dominate.
1095     SmallVector<Instruction *, 4> NotHoisting;
1096 
1097     for (Instruction &I : *FC1Preheader) {
1098       // Can't move a branch
1099       if (&I == FC1Preheader->getTerminator())
1100         continue;
1101       // If the instruction has side-effects, give up.
1102       // TODO: The case of mayReadFromMemory we can handle but requires
1103       // additional work with a dependence analysis so for now we give
1104       // up on memory reads.
1105       if (I.mayThrow() || !I.willReturn()) {
1106         LLVM_DEBUG(dbgs() << "Inst: " << I << " may throw or won't return.\n");
1107         return false;
1108       }
1109 
1110       LLVM_DEBUG(dbgs() << "Checking Inst: " << I << "\n");
1111 
1112       if (I.isAtomic() || I.isVolatile()) {
1113         LLVM_DEBUG(
1114             dbgs() << "\tInstruction is volatile or atomic. Cannot move it.\n");
1115         return false;
1116       }
1117 
1118       if (canHoistInst(I, SafeToHoist, NotHoisting, FC0)) {
1119         SafeToHoist.push_back(&I);
1120         LLVM_DEBUG(dbgs() << "\tSafe to hoist.\n");
1121       } else {
1122         LLVM_DEBUG(dbgs() << "\tCould not hoist. Trying to sink...\n");
1123         NotHoisting.push_back(&I);
1124 
1125         if (canSinkInst(I, FC1)) {
1126           SafeToSink.push_back(&I);
1127           LLVM_DEBUG(dbgs() << "\tSafe to sink.\n");
1128         } else {
1129           LLVM_DEBUG(dbgs() << "\tCould not sink.\n");
1130           return false;
1131         }
1132       }
1133     }
1134     LLVM_DEBUG(
1135         dbgs() << "All preheader instructions could be sunk or hoisted!\n");
1136     return true;
1137   }
