1229   /// Return true if the dependences between @p I0 (in @p L0) and @p I1 (in
1230   /// @p L1) allow loop fusion of @p L0 and @p L1. The dependence analyses
1231   /// specified by @p DepChoice are used to determine this.
1232   bool dependencesAllowFusion(const FusionCandidate &FC0,
1233                               const FusionCandidate &FC1, Instruction &I0,
1234                               Instruction &I1, bool AnyDep,
1235                               FusionDependenceAnalysisChoice DepChoice) {
1236 #ifndef NDEBUG
1237     if (VerboseFusionDebugging) {
1238       LLVM_DEBUG(dbgs() << "Check dep: " << I0 << " vs " << I1 << " : "
1239                         << DepChoice << "\n");
1240     }
1241 #endif
1242     switch (DepChoice) {
1243     case FUSION_DEPENDENCE_ANALYSIS_SCEV:
1244       return accessDiffIsPositive(*FC0.L, *FC1.L, I0, I1, AnyDep);
1245     case FUSION_DEPENDENCE_ANALYSIS_DA: {
1246       auto DepResult = DI.depends(&I0, &I1);
1247       if (!DepResult)
1248         return true;
1249 #ifndef NDEBUG
1250       if (VerboseFusionDebugging) {
1251         LLVM_DEBUG(dbgs() << "DA res: "; DepResult->dump(dbgs());
1252                    dbgs() << " [#l: " << DepResult->getLevels() << "][Ordered: "
1253                           << (DepResult->isOrdered() ? "true" : "false")
1254                           << "]\n");
1255         LLVM_DEBUG(dbgs() << "DepResult Levels: " << DepResult->getLevels()
1256                           << "\n");
1257       }
1258 #endif
1259       unsigned Levels = DepResult->getLevels();
1260       unsigned SameSDLevels = DepResult->getSameSDLevels();
1261       unsigned CurLoopLevel = FC0.L->getLoopDepth();
1262 
1263       // Check if DA is missing info regarding the current loop level
1264       if (CurLoopLevel > Levels + SameSDLevels)
1265         return false;
1266 
1267       // Iterating over the outer levels.
1268       for (unsigned Level = 1; Level <= std::min(CurLoopLevel - 1, Levels);
1269            ++Level) {
1270         unsigned Direction = DepResult->getDirection(Level, false);
1271 
1272         // Check if the direction vector does not include equality. If an outer
1273         // loop has a non-equal direction, outer indicies are different and it
1274         // is safe to fuse.
1275         if (!(Direction & Dependence::DVEntry::EQ)) {
1276           LLVM_DEBUG(dbgs() << "Safe to fuse due to non-equal acceses in the "
1277                                "outer loops\n");
1278           NumDA++;
1279           return true;
1280         }
1281       }
1282 
1283       assert(CurLoopLevel > Levels && "Fusion candidates are not separated");
1284 
1285       unsigned CurDir = DepResult->getDirection(CurLoopLevel, true);
1286 
1287       // Check if the direction vector does not include greater direction. In
1288       // that case, the dependency is not a backward loop-carried and is legal
1289       // to fuse. For example here we have a forward dependency
1290       //    for (int i = 0; i < n; i++)
1291       //        A[i] = ...;
1292       //    for (int i = 0; i < n; i++)
1293       //        ... = A[i-1];
1294       if (!(CurDir & Dependence::DVEntry::GT)) {
1295         LLVM_DEBUG(dbgs() << "Safe to fuse with no backward loop-carried "
1296                              "dependency\n");
1297         NumDA++;
1298         return true;
1299       }
1300 
1301       if (DepResult->getNextPredecessor() || DepResult->getNextSuccessor())
1302         LLVM_DEBUG(
1303             dbgs() << "TODO: Implement pred/succ dependence handling!\n");
1304 
1305       // TODO: Can we actually use the dependence info analysis here?
1306       return false;
1307     }
1308 
1309     case FUSION_DEPENDENCE_ANALYSIS_ALL:
1310       return dependencesAllowFusion(FC0, FC1, I0, I1, AnyDep,
1311                                     FUSION_DEPENDENCE_ANALYSIS_SCEV) ||
1312              dependencesAllowFusion(FC0, FC1, I0, I1, AnyDep,
1313                                     FUSION_DEPENDENCE_ANALYSIS_DA);
1314     }
1315 
1316     llvm_unreachable("Unknown fusion dependence analysis choice!");
1317   }
